# A dictionary that stores the synonyms like cold with chills, etc..
SYNONYMS = {
    "fever":        ["fever", "high temperature", "elevated temperature", "febrile", "pyrexia", "temperature"],
    "cold":         ["cold", "chills", "feeling cold", "coldness"],
    "runny nose":   ["runny nose", "nasal discharge", "nasal drip", "nose running", "rhinorrhea"],
    "sneezing":     ["sneezing", "sneezes", "frequent sneezing", "sneezing fits"],
    "cough":        ["cough", "coughing", "coughing fits", "persistent cough"],
    "sore throat":  ["sore throat", "throat pain", "throat irritation", "scratchy throat", "throat ache"],
    "headache":     ["headache", "head pain", "head ache", "cephalgia"],
    "fatigue":      ["fatigue", "tiredness", "exhaustion", "lethargy", "low energy", "weakness"],
    "pain":         ["pain", "ache", "discomfort", "soreness"],
    "swelling":     ["swelling", "edema", "puffiness", "swollen"],
    "vomiting":     ["vomiting", "throwing up", "nausea and vomiting", "emesis"],
    "diarrhea":     ["diarrhea", "loose stools", "watery stools", "loose motions"],
    "rash":         ["rash", "skin rash", "eruption", "skin eruption"],
    "itching":      ["itching", "itchiness", "pruritus", "itchy skin"],
    "dizziness":    ["dizziness", "lightheadedness", "feeling dizzy", "vertigo"],
    "shortness of breath": ["shortness of breath", "breathlessness", "difficulty breathing", "breathless"],
    "chest pain":   ["chest pain", "chest discomfort", "chest tightness", "chest pressure"],
    "nausea":       ["nausea", "feeling nauseous", "queasy", "upset stomach", "sick feeling"],
    "burning":      ["burning", "burning sensation", "burning feeling"],
    "urination":    ["urination", "passing urine", "voiding"],
}

# Function of converting the words with synonyms
def synonym_replace(text: str) -> str:
    result = text
    for key, options in SYNONYMS.items():
        if key in result and random.random() < 0.5:
            result = result.replace(key, random.choice(options), 1)
    return result


# If user do not give any prefixes , so a function to add prefixes in the text
def add_prefix(text: str) -> str:
    prefixes = [
        "I have", "I've had", "I am experiencing", "I'm suffering from",
        "Symptoms include", "Patient reports", "I feel", "I've been having",
        "Having", "My symptoms are", "I noticed", "I've been dealing with",
    ]
    # making random choice among prefixes 
    return f"{random.choice(prefixes)} {text}"



# If user do not give duration at the end , so a function that can add duration in text
def add_duration(text: str) -> str:
    durations = [
        "since yesterday", "for 2 days", "for 3 days", "since this morning",
        "for the past week", "for a few days", "since last night",
        "for about a day", "over the past 2 days", "since 3 days ago",
    ]
    return f"{text} {random.choice(durations)}"


# Function to drop minor words 
def drop_minor_word(text: str) -> str:
    words = text.split()
    if len(words) <= 5:
        return text
    # Don't drop the first 2 words (main symptom)
    idx = random.randint(2, len(words) - 1)
    words.pop(idx)
    return " ".join(words)


# A function to augment more variants 
# to use all the above functions here in augmentation to increase the dataset 
def augment_text(text: str, n: int = 6) -> list:
    seen = {text}
    variants = [text]

    attempts = 0
    # A loop to make more variants upto 40 times 
    while len(variants) < n and attempts < 40:
        attempts += 1
        r = random.random()
        if r < 0.25:
            v = add_prefix(text)
        elif r < 0.50:
            v = add_duration(text)
        elif r < 0.65:
            v = add_prefix(add_duration(text))
        elif r < 0.80:
            v = synonym_replace(text)
        elif r < 0.90:
            v = add_prefix(synonym_replace(text))
        else:
            v = drop_minor_word(text)

        v = clean_text(v)
        if v not in seen and len(v) > 10:
            seen.add(v)
            variants.append(v)

    return variants

# Clean the text by using NLP
def clean_text(text: str) -> str:
    text = str(text).lower()
    text = text.translate(str.maketrans('', '', string.punctuation))
    text = re.sub(r"\s+", " ", text).strip()
    return text



