# the function to build the dataframe to be used in csv
def build_dataframe(augment_per_base: int = 6) -> pd.DataFrame:
    rows = []

    for disease, data in CORPUS.items():
        base_texts = data.get("base", [])
        short_texts = data.get("short", [])

        seen = set()

        # Add base texts with augmentation
        for text in base_texts:
            cleaned = clean_text(text)
            if cleaned not in seen:
                rows.append({"text": cleaned, "label": disease})
                seen.add(cleaned)

            for variant in augment_text(text, n=augment_per_base):
                cleaned_v = clean_text(variant)
                if cleaned_v not in seen and len(cleaned_v) > 8:
                    rows.append({"text": cleaned_v, "label": disease})
                    seen.add(cleaned_v)

        # Add short texts as-is (these are critical for fixing the prediction bugs)
        for text in short_texts:
            cleaned = clean_text(text)
            if cleaned not in seen:
                rows.append({"text": cleaned, "label": disease})
                seen.add(cleaned)
            # Also augment short texts lightly
            for variant in augment_text(text, n=3):
                cleaned_v = clean_text(variant)
                if cleaned_v not in seen and len(cleaned_v) > 5:
                    rows.append({"text": cleaned_v, "label": disease})
                    seen.add(cleaned_v)

    df = pd.DataFrame(rows)
    df = df.sample(frac=1, random_state=42).reset_index(drop=True)
    return df



# Main function to store the dataset in csv files and use all the above functions   

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--out", default="data", help="Output directory")
    parser.add_argument("--preview", action="store_true", help="Print stats only")
    args = parser.parse_args()

    df = build_dataframe()

    print(f"   Total rows   : {len(df):,}")
    print(f"   Unique labels: {df['label'].nunique()}")
    print(f"\n   Samples per disease:")
    vc = df["label"].value_counts()
    for disease, count in vc.items():
        bar = "█" * (count // 20)
        print(f"   {disease:<40} {count:>5}  {bar}")

    if args.preview:
        return

    from sklearn.model_selection import train_test_split
    train, test = train_test_split(df, test_size=0.2, random_state=42, stratify=df["label"])

    os.makedirs(args.out, exist_ok=True)
    train.to_csv(f"{args.out}/train.csv", index=False)
    test.to_csv(f"{args.out}/test.csv", index=False)

    label_map = {label: idx for idx, label in enumerate(sorted(df["label"].unique()))}
    with open(f"{args.out}/label_map.json", "w") as f:
        json.dump(label_map, f, indent=2)

    print(f"\n Saved to '{args.out}/'")
    print(f"   train.csv      : {len(train):,} rows")
    print(f"   test.csv       : {len(test):,} rows")
    print(f"   label_map.json : {len(label_map)} classes")


if __name__ == "__main__":
    main()